class Solution:
    def largestCombination(self, candidates):
        """
        :type candidates: List[int]
        :rtype: int
        """
        max_combination = 0

        # Check each bit position (numbers up to 10^7 need ~24 bits)
        for bit in range(24):
            count = 0
            for num in candidates:
                # Check if bit is set
                if num & (1 << bit):
                    count += 1
            max_combination = max(max_combination, count)

        return max_combination
